	//#region custom_components/hass_datapoints/src/panels/datapoints/context/persistence-context.ts
	function createHistoryPagePersistenceContext(getHass) {
		const state = {
			savingPreferences: false,
			savePageBusy: false,
			exportBusy: false
		};
		return {
			state,
			async saveUserPreferences(options) {
				const hass = getHass();
				if (!hass || state.savingPreferences) return;
				state.savingPreferences = true;
				try {
					await saveUserData(hass, options.preferencesKey, options.payload);
					options.onSuccess?.();
				} catch (error) {
					options.onError?.(error);
				} finally {
					state.savingPreferences = false;
				}
			},
			async downloadSpreadsheet(options) {
				const hass = getHass();
				if (!hass || state.exportBusy) return;
				state.exportBusy = true;
				try {
					await downloadHistorySpreadsheet({
						hass,
						entityIds: options.entityIds,
						startTime: options.startTime,
						endTime: options.endTime,
						datapointScope: options.datapointScope
					});
					options.onSuccess?.();
				} catch (error) {
					options.onError?.(error);
				} finally {
					state.exportBusy = false;
				}
			},
			async savePageState(options) {
				const hass = getHass();
				if (!hass || state.savePageBusy) return;
				state.savePageBusy = true;
				try {
					await saveUserData(hass, options.savedPageKey, options.state);
					options.onSuccess?.();
				} catch (error) {
					options.onError?.(error);
				} finally {
					state.savePageBusy = false;
				}
			},
			async restorePageState(options) {
				const hass = getHass();
				if (!hass) return;
				try {
					const saved = await fetchUserData(hass, options.savedPageKey, options.fallbackValue);
					if (!saved || typeof saved !== "object") {
						options.onMissing?.();
						return;
					}
					options.onSuccess?.(saved);
				} catch (error) {
					options.onError?.(error);
				}
			},
			async clearSavedPageState(options) {
				const hass = getHass();
				if (!hass) return;
				try {
					await saveUserData(hass, options.savedPageKey, null);
					options.onSuccess?.();
				} catch (error) {
					options.onError?.(error);
				}
			}
		};
	}
	//#endregion
	//#region custom_components/hass_datapoints/src/panels/datapoints/context/create-history-page-context.ts
	function createHistoryPageContext(hass = null) {
		const context = {
			hass,
			app: createHistoryPageAppStateContext(),
			fetch: createHistoryPageFetchContext(() => context.hass),
			persistence: createHistoryPagePersistenceContext(() => context.hass),
			orchestration: createHistoryPageOrchestrationContext(),
			navigation: createHistoryPageNavigationContext()
		};
		return context;
	}
